async function main(str) {
    // 货币映射字典
    const currencyMap = {
        '美元': 'USD',
        '$': 'USD',
        '刀': 'USD',
        '欧元': 'EUR',
        '欧元': 'EUR',
        '元': 'CNY',
        '人民币': 'CNY',
        '港币': 'HKD',
        '日元': 'JPY',
        '€': 'EUR',
        '£': 'GBP',
        '英镑': 'GBP',
        '新台币':'TWD',
        '卢比': 'INR',
        '泰铢': 'THB',
        '越南盾': 'VND',
        '比索': 'PHP',
        '法郎': 'CHF',
        // 其他货币可以在这里添加
    };
    // 将输入字符串按空格分割
    const parts = str.split(' ');
    let amount, fromCurrency, toCurrency;

    // 处理第一个部分（金额和货币）
    if (parts.length > 0) {
        amount = parts[0]; // 第一部分是金额和货币
        fromCurrency = amount.replace(/[0-9.]+/, '').trim(); // 提取货币类型
        amount = parseFloat(amount.replace(fromCurrency, '').trim()); // 提取金额
    }

    // 处理第二部分（目标货币）
    if (parts.length > 1) {
        toCurrency = parts[1]; // 第二部分是目标货币
    } else {
        toCurrency = '元'; // 默认目标货币为元
    }
    // 如果目标货币不在字典中，返回错误
    if (!currencyMap[toCurrency]) {
        throw new Error(`不支持的目标货币: ${toCurrency}`);
    }
    const fromCurrencyCode = currencyMap[fromCurrency];
    const toCurrencyCode = currencyMap[toCurrency];
    if (!fromCurrencyCode) {
        throw new Error(`不支持的源货币: ${fromCurrency}`);
    }
    try {
        const baseURL = "https://api.exchangerate-api.com/v4/latest/";
        const req = {
            url: baseURL + fromCurrencyCode,
            header: {
                'content-type': 'application/json;charset=UTF-8'
            }
        };
        // 使用 $http.get 获取汇率数据
        const response = await $http.get(req);
        const responseJson = JSON.parse(response); // 解析响应
        const rates = responseJson.rates;
        // 进行货币转换
        if (rates[toCurrencyCode]) {
            const convertedAmount = amount * rates[toCurrencyCode];
            return `${amount} ${fromCurrency} = ${convertedAmount.toFixed(2)} ${toCurrency}`;
        } else {
            throw new Error(`获取汇率失败: ${toCurrencyCode}`);
        }
    } catch (error) {
        throw new Error(`获取汇率时出错: ${error.message}`);
    }
}

