// 全局变量

const requestHeader = { 'content-type': 'application/json;charset=UTF-8' };



//文生图整合

async function main(str) {

const createListBtn = (title, req) => ({

type: 'function',

title: title,

content: 'txtToImages',

args: [req],

});



// 优化后的输入判断

const inputTxt = (str && typeof str === 'string' && str.trim() !== '') ? str : "默认文本";

return [

createListBtn('鲁迅话多', { url: encodeURI(`https://api.andeer.top/API/img_luxun.php?text=${inputTxt}`), headers: requestHeader }),

createListBtn('举黄牌子', { url: encodeURI(`https://api.andeer.top/API/jupai.php?text=${inputTxt}`), headers: requestHeader }),

createListBtn('诺基亚说', { url: encodeURI(`https://api.andeer.top/API/img_nokia.php?data=${inputTxt}`), headers: requestHeader }),

createListBtn('手写本子', { url: encodeURI(`https://api.yujn.cn/api/shouxie.php?text=${inputTxt}`), headers: requestHeader }),

createListBtn('黑丝举牌', { url: encodeURI(`http://api.yujn.cn/api/hsjp1.php?msg=${inputTxt}&rgb1=1`), headers: requestHeader }),

createListBtn('滚出QQ(输入QQ号)', { url: encodeURI(`http://api.yujn.cn/api/gun.php?qq=${inputTxt}`), headers: requestHeader }),

createListBtn('撕开QQ(输入QQ号)', { url: encodeURI(`https://api.lolimi.cn/API/si/?QQ=${inputTxt}`), headers: requestHeader }),

];

}



async function txtToImages(req) {

try {

const result = await $http.get(req);

// 尝试解析为 JSON

let jsonData;

try {

jsonData = JSON.parse(result); // 尝试解析为 JSON

//console.log("返回的结果是 JSON:", jsonData);

const imageUrl = jsonData.data; // 假设 JSON 中有一个 data 字段

//console.log(imageUrl);

const reqData = { url: encodeURI(imageUrl), headers: requestHeader };

const resultData = await $http.get(reqData);

$pb.writeImage(resultData); // 确保 resultData 是有效的图像数据

$pb.paste();

return null;

} catch (error) {

//console.error("返回的结果不是JSON:", error);

$pb.writeImage(result);

$pb.paste();

return null;

}



} catch (error) {

console.error("请求失败:", error);

}

}

async function main() {
const createMenuEntry = (title, func) => ({
type: 'js',
title: title,
content: `
(async () => {
const x = await ${func}();
console.log("${title}返回结果: " + x);
$pb.writeImage(x);
$pb.paste();
})();
`,
});

return [
createMenuEntry('黑丝一', 'getHeiSi'),
createMenuEntry('黑丝二', 'getHeiSi2'),
createMenuEntry('白丝一', 'getBaiSi'),
createMenuEntry('白丝二', 'getBaiSi2'),
createMenuEntry('福利姬', 'getFuLiJi'),
createMenuEntry('妹子腿', 'getMeiZi'),
];
}

