async function main(input) {
    // 1. 获取待处理文本（输入框优先 > 剪贴板）
    const textToProcess = await getProcessingText(input);

    // 2. 空内容处理
    if (!textToProcess) {
        return {
            type: "txt",
            content: "📭 输入框和剪贴板均为空",
            ignore: true
        };
    }

    // 3. 执行加密/解密操作
    return await processContent(textToProcess);
}

// 核心：获取处理文本（输入框 > 剪贴板）
async function getProcessingText(input) {
    // 情况1：输入框有内容（支持字符串或对象参数）
    if (typeof input === 'string' && input.trim()) {
        return input.trim();
    }
    if (input?.data?.trim()) {
        return input.data.trim();
    }

    // 情况2：检测剪贴板
    try {
        const clipboardText = await $pb.readString();
        return clipboardText?.trim() || null;
    } catch (e) {
        console.error("剪贴板读取失败:", e);
        return null;
    }
}

// 处理内容（自动判断操作类型）
async function processContent(content) {
    // 如果是加密指令
    if (content.startsWith("encrypt:")) {
        return await handleEncrypt(content.replace("encrypt:", ""));
    }

    // 如果是解密指令
    if (content.startsWith("decrypt:")) {
        return await handleDecrypt(content.replace("decrypt:", ""));
    }

    // 默认显示操作菜单
    return [
        {
            type: "function",
            content: "handleEncrypt",
            args: [content],
            title: "🔒 加密"
        },
        {
            type: "function",
            content: "handleDecrypt", 
            args: [content],
            title: "🔓 解密"
        }
    ];
}

// 加密处理
async function handleEncrypt(data) {
    try {
        const encrypted = $base64?.encode?.(data) || btoa(unescape(encodeURIComponent(data)));
        await $pb.writeString(encrypted);
        return {
            type: "txt",
            content: `${encrypted.slice(0, 50)}${encrypted.length > 50 ? "..." : ""}`
        };
    } catch (e) {
        return {
            type: "txt",
            content: `${e.message}`,
            ignore: true
        };
    }
}

// 解密处理 
async function handleDecrypt(data) {
    try {
        const decrypted = $base64?.decode?.(data) || decodeURIComponent(escape(atob(data)));
        await $pb.writeString(decrypted);
        return {
            type: "txt",
            content: `${decrypted.slice(0, 100)}${decrypted.length > 100 ? "..." : ""}`
        };
    } catch (e) {
        return {
            type: "txt", 
            content: `${e.message}`,
            ignore: true
        };
    }
}
